import React from 'react';
import { Link, graphql } from 'gatsby';

import About from '../components/about';
import Layout from '../components/layout';
import SEO from '../components/seo';
import Posts from '../components/posts';
import { rhythm } from '../utils/typography';

const publishedPredicate = ({ node }) => !node.frontmatter.draft;

class BlogIndex extends React.Component {
  render() {
    const { data } = this.props;
    const siteTitle = data.site.siteMetadata.title;
    const posts = data.allMarkdownRemark.edges.filter(publishedPredicate);

    return (
      <Layout location={this.props.location} title={siteTitle}>
        <SEO title="Home" />
        <About />
        <h1 style={{ fontSize: rhythm(1), fontWeight: 600 }}>Blog entries</h1>
        <Posts posts={posts.slice(0, 10)} />
        {posts.length > 10 ? (
          <nav
            style={{
              display: 'flex',
              justifyContent: 'flex-end',
            }}
          >
            <Link to={`/blog/page/2`}>Older →</Link>
          </nav>
        ) : null}
      </Layout>
    );
  }
}

export default BlogIndex;

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      edges {
        node {
          excerpt
          fields {
            slug
          }
          frontmatter {
            date: date(formatString: "D MMMM YYYY")
            pathDate: date(formatString: "YYYY/MM")
            slug
            title
            description
            draft
          }
        }
      }
    }
  }
`;
